import{_ as n,o as a,c as e,ae as p}from"./chunks/framework.DhtYoOpx.js";const b=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"articles/vue/react/redux的中间键原理.md","filePath":"articles/vue/react/redux的中间键原理.md","lastUpdated":1776146674000}'),l={name:"articles/vue/react/redux的中间键原理.md"};function i(t,s,r,c,o,d){return a(),e("div",null,[...s[0]||(s[0]=[p(`<h4 id="一、-概念" tabindex="-1">一、 概念： <a class="header-anchor" href="#一、-概念" aria-label="Permalink to &quot;一、 概念：&quot;">​</a></h4><p>通常来说中间件是在某个应用中 A 和 B 部分中间的那一块， 中间件可以把 A 发送数据到 B 的形式从</p><p>A -----&gt; B</p><p>变成:</p><p>A ---&gt; middleware 1 ---&gt; middleware 2 ---&gt; middleware 3 --&gt; ... ---&gt; B</p><h4 id="二、那么中间件在-redux-中是如何演变的" tabindex="-1">二、那么中间件在 Redux 中是如何演变的？ <a class="header-anchor" href="#二、那么中间件在-redux-中是如何演变的" aria-label="Permalink to &quot;二、那么中间件在 Redux 中是如何演变的？&quot;">​</a></h4><p><strong>问题：</strong> 使用 Redux 的一个益处就是它让 state 的变化过程变的可预知和透明。每当一个 action 发起完成后，新的 state 就会被计算并保存下来。State 不能被自身修改，只能由特定的 action 引起变化。</p><p>试想一下，当我们的应用中每一个 action 被发起以及每次新的 state 被计算完成时都将它们记录下来，岂不是很好？当程序出现问题时，我们可以通过查阅日志找出是哪个 action 导致了 state 不正确</p><ul><li>阶段一 ### ==手动记录==</li></ul><p>假设，你在创建一个 Todo 时这样调用：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>store.dispatch(addTodo(&#39;Use Redux&#39;))</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>为了记录这个 action 以及产生的新的 state，你可以通过这种方式记录日志：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>const action = addTodo(&#39;Use Redux&#39;)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>console.log(&#39;dispatching&#39;, action)</span></span>
<span class="line"><span>store.dispatch(action)</span></span>
<span class="line"><span>console.log(&#39;next state&#39;, store.getState())</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><ul><li>阶段二 ### ==封装 Dispatch方法==</li></ul><p>你可以将上面的操作抽取成一个函数：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>function dispatchAndLog(store, action) {</span></span>
<span class="line"><span>  console.log(&#39;dispatching&#39;, action)</span></span>
<span class="line"><span>  store.dispatch(action)</span></span>
<span class="line"><span>  console.log(&#39;next state&#39;, store.getState())</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>然后用它替换 store.dispatch():</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>dispatchAndLog(store, addTodo(&#39;Use Redux&#39;))</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>你可以选择到此为止，但是每次都要导入一个外部方法总归还是不太方便。</p><ul><li>阶段三 ### ==直接修改store的Dispatch方法==</li></ul><p>如果我们直接替换 store 实例中的 dispatch 函数会怎么样呢？</p><p>Redux store 只是一个包含一些方法的普通对象，同时我们使用的是JavaScript，因此我们可以这样实现 dispatch 的 monkeypatch：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>const next = store.dispatch</span></span>
<span class="line"><span>store.dispatch = function dispatchAndLog(action) {</span></span>
<span class="line"><span>  console.log(&#39;dispatching&#39;, action)</span></span>
<span class="line"><span>  let result = next(action)</span></span>
<span class="line"><span>  console.log(&#39;next state&#39;, store.getState())</span></span>
<span class="line"><span>  return result</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>这离我们想要的已经非常接近了！无论我们在哪里发起 action，保证都会被记录。Monkeypatching 令人感觉还是不太舒服，不过利用它我们做到了我们想要的。。</p><ul><li>阶段四 ### ==隐藏 Monkeypatching==</li></ul><p>Monkeypatching 本质上是一种 hack。“将任意的方法替换成你想要的”，此时的 API 会是什么样的呢？现在，让我们来看看这种替换的本质。 在之前，我们用自己的函数替换掉了 store.dispatch。如果我们不这样做，而是在函数中返回新的 dispatch 呢？</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>function logger(store) {</span></span>
<span class="line"><span>  const next = store.dispatch //保存原来的dispatch方法</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   &lt;!--我们之前的做法:--&gt;</span></span>
<span class="line"><span>   &lt;!-- store.dispatch = function dispatchAndLog(action) {--&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  return function dispatchAndLog(action) {</span></span>
<span class="line"><span>    console.log(&#39;dispatching&#39;, action)</span></span>
<span class="line"><span>    let result = next(action)</span></span>
<span class="line"><span>    console.log(&#39;next state&#39;, store.getState())</span></span>
<span class="line"><span>    return result</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><p>我们可以在 Redux 内部提供一个可以将实际的 monkeypatching 应用到 store.dispatch 中的辅助方法：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>function applyMiddlewareByMonkeypatching(store, middlewares) {</span></span>
<span class="line"><span>  middlewares = middlewares.slice()</span></span>
<span class="line"><span>  middlewares.reverse()</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  // 在每一个 middleware 中变换 dispatch 方法。</span></span>
<span class="line"><span>  middlewares.forEach(middleware =&gt; (store.dispatch = middleware(store)))</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>然后像这样应用多个 middleware：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>applyMiddlewareByMonkeypatching(store, [logger, crashReporter])</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>尽管我们做了很多，实现方式依旧是 monkeypatching。 因为我们仅仅是将它隐藏在我们的框架内部，并没有改变这个事实。</p><ul><li>阶段五 ### ==移除 Monkeypatching== 每次我们获取前一个dispatch是通过store.dispatch获取的，这个我们想在applyMiddlewareByMonkeypatching函数应用中间键是将store.dispatch当做参数传给中间键，这样我们就可以将Monkeypatching中的 const next = store.dispatch删除掉</li></ul><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 注意：这是简单粗暴的中间件调用方法</span></span>
<span class="line"><span>// 并 *不是* Redux API 真实的实现方法</span></span>
<span class="line"><span>function applyMiddlewareByMonkeypatching(store, middlewares) {</span></span>
<span class="line"><span>  middlewares = middlewares.slice()</span></span>
<span class="line"><span>  middlewares.reverse()</span></span>
<span class="line"><span>  let dispatch = store.dispatch</span></span>
<span class="line"><span>  // 在每一个 middleware 中变换 dispatch 方法。</span></span>
<span class="line"><span>  middlewares.forEach(middleware =&gt; (store.dispatch = middleware(store)(dispatch)))</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 中间键函数变成了</span></span>
<span class="line"><span>function logger(store) {</span></span>
<span class="line"><span>  return function wrapDispatchToAddLogging(next) {</span></span>
<span class="line"><span>    return function dispatchAndLog(action) {</span></span>
<span class="line"><span>      console.log(&#39;dispatching&#39;, action)</span></span>
<span class="line"><span>      let result = next(action)</span></span>
<span class="line"><span>      console.log(&#39;next state&#39;, store.getState())</span></span>
<span class="line"><span>      return result</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>//通过es6简化</span></span>
<span class="line"><span>const logger = store =&gt; next =&gt; action =&gt; {</span></span>
<span class="line"><span>  console.log(&#39;dispatching&#39;, action)</span></span>
<span class="line"><span>  let result = next(action)</span></span>
<span class="line"><span>  console.log(&#39;next state&#39;, store.getState())</span></span>
<span class="line"><span>  return result</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>//最终生成中间键的统一模板</span></span>
<span class="line"><span>  var anyMiddleware = function ({ dispatch,getState }) {</span></span>
<span class="line"><span>        return function(next) {</span></span>
<span class="line"><span>            return function (action) {</span></span>
<span class="line"><span>                // 你的中间件业务相关代码</span></span>
<span class="line"><span>            }</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>    }</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br><span class="line-number">33</span><br><span class="line-number">34</span><br><span class="line-number">35</span><br><span class="line-number">36</span><br></div></div><h4 id="三、那么中间件在-redux-中是如何工作的" tabindex="-1">三、那么中间件在 Redux 中是如何工作的？ <a class="header-anchor" href="#三、那么中间件在-redux-中是如何工作的" aria-label="Permalink to &quot;三、那么中间件在 Redux 中是如何工作的？&quot;">​</a></h4><p>看上去 Redux 并不能自动处理 action creator 中返回的异步函数。</p><p>但如果在 action creator 和 reducer 之间增加一个中间件，就可以把这个函数转成适合 Redux 处理的内容：</p><p>action ---&gt; dispatch---&gt; middleware 1 ---&gt; middleware 2 ---&gt; reducers</p><ul><li><p>每当一个 action（或者其他诸如异步 action creator 中的某个函数）被分发时， 我们的中间件就会被调用</p></li><li><p>并且在需要的时候协助 action creator 分发真正的 action（或者什么都不做， 有时我们需要这么做）</p></li><li><p>在 Redux 中，中间件是纯粹的函数，有明确的使用方法并且严格的遵循以下格式：</p></li></ul><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>    var anyMiddleware = function ({ dispatch,getState }) {</span></span>
<span class="line"><span>        return function(next) {</span></span>
<span class="line"><span>            return function (action) {</span></span>
<span class="line"><span>                // 你的中间件业务相关代码</span></span>
<span class="line"><span>            }</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>    }</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>如上所述，中间件由三个嵌套的函数构成（会依次调用）：</p><ul><li><ol><li>第一层向其余两层提供分发函数和 getState 函数（因为你的中间件或 action creator 可能需要从 state 中读取数据）</li></ol></li><li><ol start="2"><li>第二层提供 next 函数，它允许你显式的将处理过的输入传递给下一个中间件或 Redux(这样 Redux 才能调用所有 reducer)。</li></ol></li><li><ol start="3"><li>第三层提供从上一个中间件或从 dispatch 传递来的 action，这个 action 可以调用下一个中间件（让 action 继续流动) 或者以想要的方式处理 action。</li></ol></li></ul><p>学习过函数式编程的人可能会意识到给上述代码提供了一个机会来使用柯里化（如果你不理解也没关系，跳过接下去的 10 行，不会影响你对 redux 的理解）。</p><p><strong>使用柯里化，你可以简化上述函数：</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>     &lt;!--&quot;curry&quot; may come any functional programming library (lodash, ramda, etc.)--&gt;</span></span>
<span class="line"><span>    var thunkMiddleware = curry(</span></span>
<span class="line"><span>        ({dispatch, getState}, next, action) =&gt; (</span></span>
<span class="line"><span>             &lt;!--你的中间件业务相关代码--&gt;</span></span>
<span class="line"><span>        )</span></span>
<span class="line"><span>    );</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>我们为异步 action creator 提供的中间件叫 thunk middleware // 它的代码在：<a href="https://github.com/gaearon/redux-thunk" target="_blank" rel="noreferrer">https://github.com/gaearon/redux-thunk</a>. // 它看上去是这样 (为了可读性使用 ES5 语法书写该函数）:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>var thunkMiddleware = function ({ dispatch, getState }) {</span></span>
<span class="line"><span>     &lt;!--console.log(&#39;Enter thunkMiddleware&#39;);--&gt;</span></span>
<span class="line"><span>    return function(next) {</span></span>
<span class="line"><span>         &lt;!--console.log(&#39;Function &quot;next&quot; provided:&#39;, next);--&gt;</span></span>
<span class="line"><span>        return function (action) {</span></span>
<span class="line"><span>            &lt;!--/console.log(&#39;Handling action:&#39;, action);--&gt;</span></span>
<span class="line"><span>            return typeof action === &#39;function&#39; ?</span></span>
<span class="line"><span>                action(dispatch, getState) :</span></span>
<span class="line"><span>                next(action)</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div>`,47)])])}const m=n(l,[["render",i]]);export{b as __pageData,m as default};
